protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed: throws in EF Core 9 Cosmos provider.
    // Manage indexing via Azure Portal / Bicep / Terraform instead.

    modelBuilder.Entity<Product>().ToContainer("Products");

    // Preserve EF8 discriminator property name ("Discriminator" → EF9 default is "$type").
    // Required so existing documents and direct SQL queries referencing c.Discriminator keep working.
    modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

    // Preserve EF8 compound id format ("Product|123" → EF9 default is just "123").
    // Required so FindAsync / point-reads can locate existing 500K documents.
    modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
}

